package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParser() throws IOException {
        Reader reader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op
                })) {

            CSVParser parser = csvFormat.parse(reader);

            assertNotNull(parser);
            assertEquals(mocked.constructed().get(0), parser);
        }
    }

    @Test
    void testParseWithNullReaderThrowsNPE() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParseCreatesCSVParserWithThisInstance() throws IOException {
        Reader reader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    assertSame(csvFormat, context.arguments().get(1));
                })) {
            csvFormat.parse(reader);
        }
    }
}
